package com.fasterxml.jackson.databind.type;

import org.junit.runner.RunWith;
import cucumber.api.CucumberOptions;
import cucumber.api.junit.Cucumber;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources",
    glue = "com.fasterxml.jackson.databind.type.steps"
)
public class CucumberTest {
}

package com.fasterxml.jackson.databind.type;

import com.fasterxml.jackson.databind.type.TypeFactory;
import com.fasterxml.jackson.databind.JavaType;
import static org.junit.Assert.*;

import cucumber.api.java.en.Given;
import cucumber.api.java.en.When;
import cucumber.api.java.en.Then;

public class StepDefs {
    private TypeFactory typeFactory;
    private JavaType resultType;
    private JavaType originalType;

    @Given("^I have a default TypeFactory$")
    public void i_have_a_default_TypeFactory() throws Throwable {
        typeFactory = TypeFactory.defaultInstance();
    }

    @When("^I construct a type from the canonical string \"([^\"]*)\"$")
    public void i_construct_a_type_from_the_canonical_string(String canonicalString) throws Throwable {
        resultType = typeFactory.constructFromCanonical(canonicalString);
        originalType = resultType;
    }

    @Then("^the resulting type should be an instance of \"([^\"]*)\"$")
    public void the_resulting_type_should_be_an_instance_of(String expectedClassName) throws Throwable {
        Class<?> expectedClass = Class.forName(expectedClassName);
        assertTrue("Resulting type should be an instance of " + expectedClassName, 
                   expectedClass.isInstance(resultType));
    }

    @Then("^the raw class of the type should be \"([^\"]*)\"$")
    public void the_raw_class_of_the_type_should_be(String expectedRawClass) throws Throwable {
        Class<?> actualRawClass = resultType.getRawClass();
        assertEquals("Raw class should be " + expectedRawClass, 
                     expectedRawClass, actualRawClass.getName());
    }

    @Then("^the content type of the type should be \"([^\"]*)\"$")
    public void the_content_type_of_the_type_should_be(String expectedContentType) throws Throwable {
        JavaType contentType = resultType.getContentType();
        if (contentType != null) {
            assertEquals("Content type should be " + expectedContentType,
                         expectedContentType, contentType.getRawClass().getName());
        } else {
            // If content type is null, check if expected was also null
            assertEquals("Content type should be null", expectedContentType, "null");
        }
    }

    @Then("^the canonical string of the type should be \"([^\"]*)\"$")
    public void the_canonical_string_of_the_type_should_be(String expectedCanonicalString) throws Throwable {
        String actualCanonicalString = resultType.toCanonical();
        assertEquals("Canonical string should be " + expectedCanonicalString,
                     expectedCanonicalString, actualCanonicalString);
    }

    @Then("^constructing a type from \"([^\"]*)\" should yield a type equal to the original type$")
    public void constructing_a_type_from_should_yield_a_type_equal_to_the_original_type(String canonicalString) throws Throwable {
        JavaType newType = typeFactory.constructFromCanonical(canonicalString);
        assertEquals("The types should be equal", originalType, newType);
    }
}
